using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notepad = new Notepad();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        SearchWeb,
        name: "search_web",
        description: "Search the web for information on a query. Returns a list of result snippets."),
    AIFunctionFactory.Create(
        notepad.SaveNote,
        name: "save_note",
        description: "Save a research note with a title and body for later reference."),
    AIFunctionFactory.Create(
        notepad.GetNotes,
        name: "get_notes",
        description: "Retrieve all saved research notes."),
};

// --- Chat client (MEAI abstraction over OpenAI) ------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent (Microsoft Agent Framework) ---------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. Given a topic you must:
        1. Use search_web to find relevant information (make several varied searches).
        2. Use save_note to record the key findings from each search.
        3. After gathering enough information, use get_notes to review everything.
        4. Provide a well-structured summary with sections, citing the sources you found.
        Be thorough but concise. Always search before summarizing.
        """,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings.",
    tools: tools);

// --- Run ---------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 60));
Console.WriteLine();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}"))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"Research complete. {notepad.Count} note(s) saved during research.");

// --- Tool implementations ----------------------------------------------------

[Description("Searches the web for information and returns result snippets.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    Console.ResetColor();

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "ResearchAgent/1.0 (dotnet; research-demo)");
    http.Timeout = TimeSpan.FromSeconds(10);

    try
    {
        // Use DuckDuckGo Instant Answer API (no key required)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await http.GetStringAsync(url);

        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;
        var results = new List<string>();

        // Abstract (main answer)
        var abstractText = root.GetProperty("Abstract").GetString();
        var abstractSource = root.GetProperty("AbstractSource").GetString();
        var abstractUrl = root.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.Add($"[{abstractSource}] {abstractText} (Source: {abstractUrl})");
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var related))
        {
            foreach (var item in related.EnumerateArray().Take(5))
            {
                var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.Add($"{text} (Source: {firstUrl})");
                }
            }
        }

        if (results.Count == 0)
        {
            return $"No detailed results found for \"{query}\". Try rephrasing the query.";
        }

        return string.Join("\n\n", results);
    }
    catch (Exception ex)
    {
        return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
    }
}

// --- Notepad (in-memory note storage) ----------------------------------------

sealed class Notepad
{
    private readonly List<(string Title, string Body, DateTime Timestamp)> _notes = [];

    public int Count => _notes.Count;

    [Description("Saves a research note with a title and body.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        _notes.Add((title, body, DateTime.UtcNow));

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        Console.ForegroundColor = ConsoleColor.DarkGreen;
        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ({n.Timestamp:u}) ---\n{n.Body}"));
    }
}

