 [Description("Searches the web for information and returns result snippets.")]
 static async Task<string> SearchWeb(
     [Description("The search query")] string query)
 {
     Console.ForegroundColor = ConsoleColor.DarkCyan;
     Console.WriteLine($"  🔍 Searching: \"{query}\"");
     Console.ResetColor();

     using var http = new HttpClient();
     http.DefaultRequestHeaders.UserAgent.ParseAdd(
         "ResearchAgent/1.0 (dotnet; research-demo)");
     http.Timeout = TimeSpan.FromSeconds(10);

     try
     {
         // Use DuckDuckGo Instant Answer API (no key required)
         var encoded = Uri.EscapeDataString(query);
         var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
         var json = await http.GetStringAsync(url);

         using var doc = JsonDocument.Parse(json);
         var root = doc.RootElement;
         var results = new List<string>();

         // Abstract (main answer)
         var abstractText = root.GetProperty("Abstract").GetString();
         var abstractSource = root.GetProperty("AbstractSource").GetString();
         var abstractUrl = root.GetProperty("AbstractURL").GetString();
         if (!string.IsNullOrWhiteSpace(abstractText))
         {
             results.Add($"[{abstractSource}] {abstractText} (Source: {abstractUrl})");
         }

         // Related topics
         if (root.TryGetProperty("RelatedTopics", out var related))
         {
             foreach (var item in related.EnumerateArray().Take(5))
             {
                 var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                 var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                 if (!string.IsNullOrWhiteSpace(text))
                 {
                     results.Add($"{text} (Source: {firstUrl})");
                 }
             }
         }

         if (results.Count == 0)
         {
             return $"No detailed results found for \"{query}\". Try rephrasing the query.";
         }

         return string.Join("\n\n", results);
     }
     catch (Exception ex)
     {
         return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
     }
 }

