             return "No notes saved yet.";
         }

         Console.ForegroundColor = ConsoleColor.DarkGreen;
         Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
         Console.ResetColor();

         return string.Join("\n\n", _notes.Select((n, i) =>
             $"--- Note #{i + 1}: {n.Title} ({n.Timestamp:u}) ---\n{n.Body}"));
     }
 }

